SELECT [ClientiConVenduto-Step0].[Delete Reason], Item.[Season Code], Item.[Trademark Code], [ClientiConVenduto-Step0].Salesperson, [ClientiConVenduto-Step0].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Address 2], Customer.City, Customer.[Post Code], Customer.County, Customer.[Country Code], Customer.[Phone No_], Customer.[Telex No_], Customer.[Fax No_], Customer.[Reservation Priority], Val([Credit Limit (LCY)]) AS LimiteCredito, Customer.[Payment Terms Code], Customer.[Payment Method Code], Sum(Val([No_ of Pairs])) AS PairsTotal, Sum([ClientiConVenduto-Step0].SalesValue) AS Venduto, IIf([venduto]-[limitecredito]>0,[venduto]-[limitecredito],0) AS Esposizione, NoteOrdiniVenditaGlobaleZFinale.listacommenti, Customer.[Blocked For Assignement], Customer.[E-Mail]
FROM (([ClientiConVenduto-Step0] INNER JOIN Item ON [ClientiConVenduto-Step0].No_ = Item.No_) INNER JOIN Customer ON [ClientiConVenduto-Step0].[Sell-to Customer No_] = Customer.No_) INNER JOIN NoteOrdiniVenditaGlobaleZFinale ON [ClientiConVenduto-Step0].[Sell-to Customer No_] = NoteOrdiniVenditaGlobaleZFinale.CodiceCliente
GROUP BY [ClientiConVenduto-Step0].[Delete Reason], Item.[Season Code], Item.[Trademark Code], [ClientiConVenduto-Step0].Salesperson, [ClientiConVenduto-Step0].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Address 2], Customer.City, Customer.[Post Code], Customer.County, Customer.[Country Code], Customer.[Phone No_], Customer.[Telex No_], Customer.[Fax No_], Customer.[Reservation Priority], Val([Credit Limit (LCY)]), Customer.[Payment Terms Code], Customer.[Payment Method Code], NoteOrdiniVenditaGlobaleZFinale.listacommenti, Customer.[Blocked For Assignement], Customer.[E-Mail]
HAVING ((([ClientiConVenduto-Step0].[Delete Reason])=""));

